#include "NetInfoWriter.h"
#include <fstream>
void writeNetInfo(const std::string& path,const RouterDB&,const std::vector<NetRouteResult>& results){std::ofstream o(path); for(auto&r:results){o<<"NET "<<r.net_name<<"\n  type: "<<(r.is_3d?"3D":"2D")<<"\n  success: "<<r.success<<"\n"; o<<"  tree_nodes:\n"; for(size_t i=0;i<r.tree_nodes.size();++i){auto&n=r.tree_nodes[i]; o<<"    - index: "<<i<<" parent_index: "<<n.parent_index<<" x: "<<n.point.x<<" y: "<<n.point.y<<" die: "<<(int)n.point.die<<" incoming_hbt_res: "<<n.incoming_hbt_res<<" incoming_hbt_cap: "<<n.incoming_hbt_cap<<"\n";} o<<"  segments:\n"; for(size_t i=0;i<r.segments.size();++i){auto&s=r.segments[i]; o<<"    - index: "<<i<<" p1:("<<s.p1.x<<","<<s.p1.y<<","<<(int)s.p1.die<<") p2:("<<s.p2.x<<","<<s.p2.y<<","<<(int)s.p2.die<<") uses_hbt: "<<s.uses_hbt<<" hbt_id: "<<s.hbt_id<<"\n";} o<<"  metrics: avg_sink_delay="<<r.delay_summary.avg_sink_delay<<" max_sink_delay="<<r.delay_summary.max_sink_delay<<" worst_sink="<<r.delay_summary.max_delay_pin_name<<"\n\n"; }}
